15	function svg({ before, after }) {
16	  const rows = [
17	    ["Status", before.status, after.status],
18	    ["Owner", before.owner, after.owner],
19	    ["Next", before.nextStep, after.nextStep],
20	    ["Risk", before.riskSummary, after.riskSummary],
21	    ["Tasks", before.tasks, after.tasks],
22	    ["Audit", before.history, after.history]
23	  ];
24	  const esc = (value) => String(value).replaceAll("&", "&amp;").replaceAll("<", "&lt;").replaceAll(">", "&gt;");
25	  const body = rows.map((row, index) => {
26	    const y = 160 + index * 58;
27	    return `<text x="52" y="${y}" class="k">${esc(row[0])}</text><text x="180" y="${y}" class="v">${esc(row[1])}</text><text x="620" y="${y}" class="g">${esc(row[2])}</text>`;
28	  }).join("");
29	  return `<svg xmlns="http://www.w3.org/2000/svg" width="1080" height="560" viewBox="0 0 1080 560">
30	    <style>.bg{fill:#0f1412}.card{fill:#f5f1e8;stroke:#d9d2bf}.h{font:800 28px system-ui;fill:#f5f1e8}.s{font:600 14px system-ui;fill:#b9c1b1}.k{font:700 14px system-ui;fill:#5a6256}.v{font:650 14px system-ui;fill:#171b17}.g{font:750 14px system-ui;fill:#087a4a}.line{stroke:#d9d2bf}</style>
31	    <rect class="bg" width="1080" height="560"/>
32	    <text x="40" y="50" class="h">AST-Bench Workflow State</text>
33	    <text x="40" y="78" class="s">postgres target / deterministic fixture / captured by render script</text>
34	    <rect x="36" y="104" width="1008" height="390" rx="6" class="card"/>
35	    <text x="180" y="124" class="k">Before</text><text x="620" y="124" class="k">After</text>
36	    <line x1="150" y1="134" x2="150" y2="470" class="line"/><line x1="590" y1="134" x2="590" y2="470" class="line"/>
37	    ${body}
38	  </svg>`;
39	}
